class AnimatedCountText extends StatelessWidget {
  const AnimatedCountText({
    super.key,
    required this.value,
    required this.style,
    this.isMoney = false,
  });

  final double value;
  final TextStyle? style;
  final bool isMoney;

  @override
  Widget build(BuildContext context) {
    return TweenAnimationBuilder<double>(
      tween: Tween<double>(begin: 0, end: value),
      duration: const Duration(milliseconds: 700),
      builder: (context, val, _) {
        final text = isMoney ? val.toStringAsFixed(0) : val.toStringAsFixed(0);
        return Text(text, style: style);
      },
    );
  }
}

FlTitlesData _chartTitles(List<DashboardSeriesPoint> points) {
  return FlTitlesData(
    topTitles: const AxisTitles(sideTitles: SideTitles(showTitles: false)),
    rightTitles: const AxisTitles(sideTitles: SideTitles(showTitles: false)),
    leftTitles: const AxisTitles(sideTitles: SideTitles(showTitles: false)),
    bottomTitles: AxisTitles(
      sideTitles: SideTitles(
        showTitles: true,
        reservedSize: 28,
        interval: points.length <= 6 ? 1 : (points.length / 6).ceilToDouble(),
        getTitlesWidget: (value, meta) {
          final index = value.toInt();
          if (index < 0 || index >= points.length) {
            return const SizedBox.shrink();
          }
          return SideTitleWidget(
            axisSide: meta.axisSide,
            child: Text(points[index].label, style: const TextStyle(fontSize: 10)),
          );
        },
      ),
    ),
  );
}

List<FlSpot> _toSpots(List<DashboardSeriesPoint> points) {
  if (points.isEmpty) {
    return [const FlSpot(0, 0)];
  }
  return points.asMap().entries.map((entry) {
    return FlSpot(entry.key.toDouble(), entry.value.value);
  }).toList();
}

List<BarChartGroupData> _toBarGroups(List<DashboardSeriesPoint> points, Color color) {
  if (points.isEmpty) {
    return [
      BarChartGroupData(x: 0, barRods: [BarChartRodData(toY: 0, color: color)])
    ];
  }
  return points.asMap().entries.map((entry) {
    return BarChartGroupData(
      x: entry.key,
      barRods: [
        BarChartRodData(toY: entry.value.value, color: color, width: 10),
      ],
    );
  }).toList();
}

const _cardDecoration = BoxDecoration(
  color: Colors.white,
  borderRadius: BorderRadius.all(Radius.circular(18)),
  boxShadow: [
    BoxShadow(color: Color(0x11000000), blurRadius: 10, offset: Offset(0, 6)),
  ],
);

const List<Color> _chartPalette = [
  Color(0xFF4C6FFF),
  Color(0xFF00C2A8),
  Color(0xFFFFB020),
  Color(0xFFE85C6C),
  Color(0xFF8B5CF6),
];

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:google_fonts/google_fonts.dart';

import 'app/admin_shell.dart';
import 'app/providers.dart';
import 'core/api_client.dart';
import 'core/session_storage.dart';
import 'features/auth/presentation/admin_login_screen.dart';

Future<void> main() async {
  WidgetsFlutterBinding.ensureInitialized();
  final storage = SessionStorage();
  final client = await ApiClient.create(storage);
  runApp(
    ProviderScope(
      overrides: [
        sessionStorageProvider.overrideWithValue(storage),
        apiClientProvider.overrideWithValue(client),
      ],
      child: const MyApp(),
    ),
  );
}

class MyApp extends StatelessWidget {
  const MyApp({super.key});

  Future<bool> _hasToken() async {
    final storage = SessionStorage();
    final token = await storage.getToken();
    return token != null && token.isNotEmpty;
  }

  ThemeData _buildTheme(Brightness brightness) {
    final base = ThemeData(
      useMaterial3: true,
      brightness: brightness,
      colorSchemeSeed: const Color(0xFF4C6FFF),
      scaffoldBackgroundColor:
          brightness == Brightness.light ? const Color(0xFFF5F7FB) : null,
    );

    return base.copyWith(
      textTheme: GoogleFonts.beVietnamProTextTheme(base.textTheme),
      appBarTheme: base.appBarTheme.copyWith(
        centerTitle: false,
        titleTextStyle: GoogleFonts.beVietnamPro(
          fontSize: 18,
          fontWeight: FontWeight.w700,
          color: base.colorScheme.onSurface,
        ),
      ),
      bottomNavigationBarTheme: base.bottomNavigationBarTheme.copyWith(
        selectedItemColor: base.colorScheme.primary,
        unselectedItemColor: base.colorScheme.onSurfaceVariant,
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Quản trị Bookstore',
      theme: _buildTheme(Brightness.light),
      darkTheme: _buildTheme(Brightness.dark),
      themeMode: ThemeMode.system,
      home: FutureBuilder<bool>(
        future: _hasToken(),
        builder: (context, snapshot) {
          if (!snapshot.hasData) {
            return const Scaffold(
              body: Center(child: CircularProgressIndicator()),
            );
          }
          final loggedIn = snapshot.data!;
          return loggedIn ? const AdminShell() : const AdminLoginScreen();
        },
      ),
    );
  }
}

import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:google_fonts/google_fonts.dart';

import 'app/admin_shell.dart';
import 'app/providers.dart';
import 'core/api_client.dart';
import 'core/session_storage.dart';
import 'features/auth/presentation/admin_login_screen.dart';

Future<void> main() async {
  WidgetsFlutterBinding.ensureInitialized();
  runApp(const BootstrapApp());
}

class BootstrapApp extends StatelessWidget {
  const BootstrapApp({super.key});

  Future<_BootstrapData> _init() async {
    final storage = SessionStorage();
    final client = await ApiClient.create(storage);
    return _BootstrapData(storage: storage, client: client);
  }

  @override
  Widget build(BuildContext context) {
    return FutureBuilder<_BootstrapData>(
      future: _init(),
      builder: (context, snapshot) {
        if (!snapshot.hasData) {
          return const MaterialApp(
            home: Scaffold(
              body: Center(child: CircularProgressIndicator()),
            ),
          );
        }
        final data = snapshot.data!;
        return ProviderScope(
          overrides: [
            sessionStorageProvider.overrideWithValue(data.storage),
            apiClientProvider.overrideWithValue(data.client),
          ],
          child: MyApp(storage: data.storage),
        );
      },
    );
  }
}

class _BootstrapData {
  const _BootstrapData({required this.storage, required this.client});

  final SessionStorage storage;
  final ApiClient client;
}

class MyApp extends StatelessWidget {
  const MyApp({super.key, required this.storage});

  final SessionStorage storage;

  Future<bool> _hasToken() async {
    final token = await storage.getToken();
    return token != null && token.isNotEmpty;
  }

  ThemeData _buildTheme(Brightness brightness) {
    final base = ThemeData(
      useMaterial3: true,
      brightness: brightness,
      colorSchemeSeed: const Color(0xFF4C6FFF),
      scaffoldBackgroundColor:
          brightness == Brightness.light ? const Color(0xFFF5F7FB) : null,
    );

    return base.copyWith(
      textTheme: GoogleFonts.beVietnamProTextTheme(base.textTheme),
      appBarTheme: base.appBarTheme.copyWith(
        centerTitle: false,
        titleTextStyle: GoogleFonts.beVietnamPro(
          fontSize: 18,
          fontWeight: FontWeight.w700,
          color: base.colorScheme.onSurface,
        ),
      ),
      bottomNavigationBarTheme: base.bottomNavigationBarTheme.copyWith(
        selectedItemColor: base.colorScheme.primary,
        unselectedItemColor: base.colorScheme.onSurfaceVariant,
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Quản trị Bookstore',
      theme: _buildTheme(Brightness.light),
      darkTheme: _buildTheme(Brightness.dark),
      themeMode: ThemeMode.system,
      home: FutureBuilder<bool>(
        future: _hasToken(),
        builder: (context, snapshot) {
          if (!snapshot.hasData) {
            return const Scaffold(
              body: Center(child: CircularProgressIndicator()),
            );
          }
          final loggedIn = snapshot.data!;
          return loggedIn ? const AdminShell() : const AdminLoginScreen();
        },
      ),
    );
  }
}
